  1	// Mostly just a copy-paste from patternfly.
  2	import * as React from 'react';
  3	import { ChartLegendTooltipStyles } from '@patternfly/react-charts/dist/js/components/ChartTheme/ChartStyles';
  4	import {
  5	  getLegendTooltipSize,
  6	  getLegendTooltipDataProps,
  7	  getLegendTooltipVisibleData,
  8	  getLegendTooltipVisibleText,
  9	} from '@patternfly/react-charts/dist/js/components/ChartUtils/chart-tooltip';
 10	import { defaults } from 'lodash-es';
 11	//@ts-ignore
 12	import { Helpers } from 'victory-core';
 13	import {
 14	  ChartLegend,
 15	  ChartLabel,
 16	  getTheme,
 17	  ChartLegendTooltipContentProps,
 18	  ChartLegendTooltipProps,
 19	  ChartCursorTooltip,
 20	  ChartTooltip,
 21	  ChartLegendTooltipLabelProps,
 22	} from '@patternfly/react-charts';
 23	import { DataPoint } from '../utils';
 24	
 25	export const ChartLegendTooltipContent: React.FunctionComponent<
 26	  ChartLegendTooltipContentProps & {
 27	    stack?: boolean;
 28	    mainDataName?: string;
 29	  }
 30	> = (props) => {
 31	  const {
 32	    activePoints,
 33	    center,
 34	    dx = 0,
 35	    dy = 0,
 36	    flyoutHeight,
 37	    flyoutWidth,
 38	    height,
 39	    labelComponent = <ChartLegendTooltipLabel />,
 40	    legendComponent = <ChartLegend />,
 41	    legendData,
 42	    text,
 43	    themeColor,
 44	    title,
 45	    titleComponent = <ChartLabel />,
 46	    width,
 47	    stack,
 48	    mainDataName,
 49	    // destructure last
 50	    theme = getTheme(themeColor),
 51	    ...rest
 52	  } = props;
 53	
 54	  const pointerLength = theme?.tooltip
 55	    ? Helpers.evaluateProp(theme.tooltip.pointerLength, props)
 56	    : 10;
 57	  const legendProps = getLegendTooltipDataProps(legendComponent.props);
 58	  const visibleLegendData = getLegendTooltipVisibleData({
 59	    activePoints,
 60	    colorScale: legendProps.colorScale,
 61	    legendData,
 62	    text,
 63	    theme,
 64	  });
 65	
 66	  const hasMainData = mainDataName
 67	    ? activePoints[0].childName === mainDataName
 68	    : false;
 69	
 70	  if (stack) {
 71	    visibleLegendData.reverse();
 72	  } else if (hasMainData) {
 73	    visibleLegendData.shift();
 74	  }
 75	
 76	  // Component offsets
 77	  const legendOffsetX = 0;
 78	  const legendOffsetY = title ? 9 : -10;
 79	  const titleOffsetX = 10;
 80	  const titleOffsetY = 0;
 81	
 82	  // Returns x position of flyout
 83	  const getX = () => {
 84	    if (!(center || flyoutWidth || width)) {
 85	      const x = (rest as any).x;
 86	      return x ? x : undefined;
 87	    }
 88	    const finalFlyoutWidth = Helpers.evaluateProp(flyoutWidth, props);
 89	    if (width > center.x + finalFlyoutWidth + pointerLength) {
 90	      return center.x + ChartLegendTooltipStyles.flyout.padding / 2;
 91	    } else if (center.x < finalFlyoutWidth + pointerLength) {
 92	      return ChartLegendTooltipStyles.flyout.padding / 2 - pointerLength;
 93	    }
 94	    return center.x - finalFlyoutWidth;
 95	  };
 96	
 97	  // Returns y position
 98	  const getY = () => {
 99	    if (!(center || flyoutHeight || height)) {
100	      const y = (rest as any).y;
101	      return y ? y : undefined;
102	    }
103	    const finalFlyoutHeight = Helpers.evaluateProp(flyoutHeight, props);
104	    if (center.y < finalFlyoutHeight / 2) {
105	      return ChartLegendTooltipStyles.flyout.padding / 2;
106	    } else if (center.y > height - finalFlyoutHeight / 2) {
107	      return (
108	        height - finalFlyoutHeight + ChartLegendTooltipStyles.flyout.padding / 2
109	      );
110	    }
111	    return (
112	      center.y -
113	      finalFlyoutHeight / 2 +
114	      ChartLegendTooltipStyles.flyout.padding / 2
115	    );
116	  };
117	
118	  // Min & max dimensions do not include flyout padding
119	  const maxLegendDimensions = getLegendTooltipSize({
120	    legendData: visibleLegendData,
121	    legendProps,
122	    text: getLegendTooltipVisibleText({ activePoints, legendData, text }),
123	    theme,
124	  });
125	  const minLegendDimensions = getLegendTooltipSize({
126	    legendData: [{ name: '' }],
127	    legendProps,
128	    theme,
129	  });
130	
131	  // Returns the label component
132	  const getLabelComponent = () =>
133	    React.cloneElement(labelComponent, {
134	      dx: maxLegendDimensions.width - minLegendDimensions.width,
135	      legendData: visibleLegendData,
136	      ...labelComponent.props,
137	    });
138	
139	  // Returns the title component
140	  const getTitleComponent = () => {
141	    const titleText = title instanceof Function ? title(activePoints) : title;
142	
143	    return React.cloneElement(titleComponent, {
144	      style: {
145	        fill: ChartLegendTooltipStyles.label.fill,
146	      },
147	      text: titleText,
148	      textAnchor: 'start',
149	      x: getX() + titleOffsetX + Helpers.evaluateProp(dx, props),
150	      y: getY() + titleOffsetY + Helpers.evaluateProp(dy, props),
151	      ...titleComponent.props,
152	    });
153	  };
154	
155	  const tooltipLegendData = getLegendTooltipVisibleData({
156	    activePoints,
157	    colorScale: legendProps.colorScale,
158	    legendData,
159	    text,
160	    textAsLegendData: true,
161	    theme,
162	  });
163	
164	  if (stack) {
165	    tooltipLegendData.reverse();
166	  } else if (hasMainData) {
167	    tooltipLegendData.shift();
168	  }
169	
170	  // Returns the legend component
171	  const getLegendComponent = () =>
172	    React.cloneElement(legendComponent, {
173	      data: tooltipLegendData,
174	      labelComponent: getLabelComponent(),
175	      standalone: false,
176	      theme,
177	      x: getX() + legendOffsetX + Helpers.evaluateProp(dx, props),
178	      y: getY() + legendOffsetY + Helpers.evaluateProp(dy, props),
179	      ...legendProps,
180	    });
181	
182	  return (
183	    <>
184	      {getTitleComponent()}
185	      {getLegendComponent()}
186	    </>
187	  );
188	};
189	ChartLegendTooltipContent.displayName = 'ChartLegendTooltipContent';
190	
191	export const ChartLegendTooltipLabel: React.FunctionComponent<
192	  ChartLegendTooltipLabelProps
193	> = ({
194	  index = 0,
195	  legendData,
196	  style,
197	  text,
198	  textAnchor = 'start',
199	  x,
200	  y,
201	
202	  // destructure last
203	  ...rest
204	}: ChartLegendTooltipLabelProps) => {
205	  const getStyle = (styles: any) => {
206	    const applyDefaultStyle = (customStyle: React.CSSProperties) =>
207	      defaults(
208	        {
209	          ...customStyle,
210	        },
211	        {
212	          fill: ChartLegendTooltipStyles.label.fill,
213	        }
214	      );
215	    return Array.isArray(styles)
216	      ? styles.map(applyDefaultStyle)
217	      : applyDefaultStyle(styles);
218	  };
219	
220	  const label =
221	    legendData && legendData.length ? legendData[index as any].name : undefined;
222	  return (
223	    <ChartLabel
224	      style={getStyle(style)}
225	      text={`${text} ${label}`}
226	      textAnchor={textAnchor}
227	      x={x}
228	      y={y}
229	      {...rest}
230	      dx={undefined}
231	    />
232	  );
233	};
234	ChartLegendTooltipLabel.displayName = 'ChartLegendTooltipLabel';
235	
236	export const ChartLegendTooltip: React.FunctionComponent<
237	  Omit<ChartLegendTooltipProps, 'title'> & {
238	    stack?: boolean;
239	    formatDate: (data: DataPoint<Date>[]) => string;
240	    getLabel?: (prop: { datum: DataPoint<Date> }) => string;
241	    mainDataName: string;
242	  }
243	> = (props) => {
244	  const {
245	    activePoints,
246	    datum,
247	    center = { x: 0, y: 0 },
248	    flyoutHeight,
249	    flyoutWidth,
250	    height,
251	    isCursorTooltip = true,
252	    mainDataName,
253	    labelComponent = <ChartLegendTooltipContent mainDataName={mainDataName} />,
254	    legendData,
255	    text,
256	    themeColor,
257	    width,
258	    stack,
259	    formatDate,
260	    getLabel,
261	    // destructure last
262	    theme = getTheme(themeColor),
263	    ...rest
264	  } = props;
265	
266	  const title = (d) => {
267	    if (stack) {
268	      return formatDate(d);
269	    }
270	    const mainDatum = mainDataName
271	      ? d.find((uDatum) => uDatum.childName === mainDataName)
272	      : d[0];
273	    return mainDatum
274	      ? getLabel({ datum: mainDatum })
275	      : `No ${mainDataName || 'data'} available`;
276	  };
277	  const pointerLength = theme?.tooltip
278	    ? Helpers.evaluateProp(theme.tooltip.pointerLength, props)
279	    : 10;
280	  const legendTooltipProps = {
281	    legendData: getLegendTooltipVisibleData({
282	      activePoints,
283	      legendData,
284	      text,
285	      theme,
286	    }),
287	    legendProps: getLegendTooltipDataProps(
288	      labelComponent.props.legendComponent
289	    ),
290	    text: getLegendTooltipVisibleText({
291	      activePoints,
292	      legendData,
293	      text,
294	    }) as any[],
295	    theme,
296	  };
297	
298	  // Returns flyout height based on legend size
299	  const getFlyoutHeight = () => {
300	    const sizeProps = stack
301	      ? legendTooltipProps
302	      : {
303	          ...legendTooltipProps,
304	          // For non-stack graphs, remove the text for "mainDataName"
305	          text: legendTooltipProps.text?.filter(
306	            (_t, i) => legendTooltipProps.legendData[i].name !== mainDataName
307	          ),
308	        };
309	    const legendFlyoutHeight =
310	      getLegendTooltipSize(sizeProps).height +
311	      ChartLegendTooltipStyles.flyout.padding;
312	    return title ? legendFlyoutHeight + 4 : legendFlyoutHeight - 10;
313	  };
314	
315	  // Returns flyout width based on legend size
316	  const getFlyoutWidth = () =>
317	    getLegendTooltipSize(legendTooltipProps).width +
318	    ChartLegendTooltipStyles.flyout.padding +
319	    (stack ? 20 : 0);
320	
321	  // Returns the tooltip content component
322	  const getTooltipContentComponent = () =>
323	    React.cloneElement(labelComponent, {
324	      center,
325	      flyoutHeight: flyoutHeight || getFlyoutHeight(),
326	      flyoutWidth: flyoutWidth || getFlyoutWidth(),
327	      height,
328	      legendData,
329	      title,
330	      width,
331	      stack,
332	      ...labelComponent.props,
333	    });
334	
335	  // Returns the tooltip component
336	  const getTooltipComponent = () => {
337	    const legendFlyoutWidth = getFlyoutWidth();
338	    const tooltipComponent = isCursorTooltip ? (
339	      <ChartCursorTooltip />
340	    ) : (
341	      <ChartTooltip constrainToVisibleArea />
342	    );
343	    return React.cloneElement(tooltipComponent, {
344	      activePoints,
345	      center,
346	      datum,
347	      flyoutHeight: flyoutHeight || getFlyoutHeight(),
348	      flyoutWidth: flyoutWidth || getFlyoutWidth(),
349	      height,
350	      labelComponent: getTooltipContentComponent(),
351	      ...(flyoutWidth === undefined && {
352	        showPointer:
353	          width > legendFlyoutWidth + center.x + pointerLength ||
354	          center.x > legendFlyoutWidth + pointerLength,
355	      }),
356	      text,
357	      theme,
358	      width,
359	      ...rest,
360	    });
361	  };
362	
363	  return getTooltipComponent();
364	};
365	ChartLegendTooltip.displayName = 'ChartLegendTooltip';

